import type { Request, Response, NextFunction } from "express";

import { databaseErrorConverter } from "@utils/error-helpers";
import type { SearchOrdersRequest } from "@api/api"
import type { IOrder } from "@models/orders";
import OrderService from "@services/orders";

/**
 * Query parameters generated by the search form (they are the same as SearchOrdersRequest keys)
 */
export type IGetAllOrdersQuery = Partial<Record<keyof SearchOrdersRequest, string>>;

/**
 * Get ALL orders info
 * Only of current user if NOT admin
 *
 * @param request
 * @param response
 * @param next
 */
export const pageAllOrders = async (
    // Page can be param or query
    request: Request<{ page?: string }, unknown, unknown, IGetAllOrdersQuery>,
    response: Response,
    next: NextFunction,
) => {
    const pageSize = Number.parseInt(process.env.NODE_SETTINGS_PAGINATION_PAGE_SIZE ?? "10");
    const page = Number.parseInt(request.params.page ?? request.query.page ?? "1");
    // Non-admin users can only see their own orders
    const scope: Partial<IOrder> = request.session.user?.admin
        ? {}
        : { userId: request.session.user?.id };
    return OrderService.search(
        {
            ...request.query,
            page,
            pageSize,
        },
        scope,
    )
        .then(({ items, meta }) =>
            response.render("orders/list", {
                pageMetaTitle: "All Orders",
                pageMetaLinks: [ "/css/order-list.css" ],
                orderList: items,
                itemsTotal: meta.totalItems,
                pageCurrent: meta.page,
                pageTotal: meta.totalPages,
                search: request.query,
            })
        )
        .catch((error: Error) => next(databaseErrorConverter(error)));
};